starter.javascript:
let size = 15;    // items still in play
let checks = 0;   // checks made so far
// each check lets you throw away half: halve size and add 1 to checks
// keep going until size reaches 0, then print checks

reference.javascript:
let size = 15;
let checks = 0;
while (size > 0) {
  checks = checks + 1;
  size = Math.floor(size / 2);
}
console.log(checks);

